需求现在拥有了一个121117条 id::::url 的final_hashs.txt文件需要读取里面的url并下载对应的视频，有如下要求： 随时可手动停止下载，再次开始下载可继续上次任务 保存下载成功的视频id，保存下载失败(链接失效或下载超时)的视频id::::url 自定义下载路径download_2.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374757677787980818283848586878889#可间断性地下载final_urls.txt的链接获得视频集import urllib.requestdef getLines(file_name): #获取文件行数 count = 0 thefile = open(file_name, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) while True: buffer = thefile.read(1024 * 8192) if not buffer: break count += buffer.count(&apos;
&apos;) thefile.close() return countdict_id_url = &#123;&#125;f = open(&quot;dict_id_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_url = eval(a)f.close()print(&quot;dict_id_url读取成功&quot;) #读取剩余urlsf_down_ok = open(&quot;down_ok.txt&quot;,&apos;a&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_down_ok_this_time = open(&quot;down_ok_this_time.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_down_ok_this_time = f_down_ok_this_time.readline() if not line_down_ok_this_time: break else: line_down_ok_this_time = line_down_ok_this_time.replace(&apos;
&apos;,&apos;&apos;) del dict_id_url[str(line_down_ok_this_time)] #更新未下载urls f_down_ok.write(str(line_down_ok_this_time)+&apos;
&apos;) #更新已下载urlsf_down_ok_this_time.close()f_down_ok.close()f_dict_id_url = open(&quot;dict_id_url.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #保存未下载的urlsf_dict_id_url.write(str(dict_id_url))f_dict_id_url.close()print(&quot;dict_id_url清理已下载urls成功&quot;)print(&quot;down_ok添加已下载urls成功&quot;)print(&quot;共剩余&quot;+str(len(dict_id_url))+&apos;条未下载&apos;)print(&quot;总共已下载&quot;+str(getLines(&apos;down_ok.txt&apos;))+&apos;条视频&apos;)f = open(&quot;down_ok_this_time.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #清空文本f.close()f_url_error = open(&quot;url_error.txt&quot;,&apos;a&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)while 1: line_url_error_this_time = f_url_error_this_time.readline() if not line_url_error_this_time: break else: f_url_error.write(str(line_url_error_this_time)) #更新失效urlsf_url_error_this_time.close()f_url_error.close()print(&quot;url_error增加错误urls成功&quot;)print(&quot;共有&quot;+str(getLines(&apos;url_error.txt&apos;))+&apos;条视频链接错误&apos;)f = open(&quot;url_error_this_time.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) #清空文本f.close()print(&apos;---开始下载---&apos;)flag = 1for key in dict_id_url: url = str(dict_id_url[key]) try: if &apos;.mp4?&apos; in url: video_name = str(key)+&apos;.mp4&apos; #视频保存路径 urllib.request.urlretrieve(url, video_name) #下载 f_down_ok_this_time = open(&quot;down_ok_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_down_ok_this_time.write(str(key)+&apos;
&apos;) f_down_ok_this_time.close() print(&apos;。。。。。&apos;) #下载成功一条打一个标记 flag += 1 else: f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_url_error_this_time.write(str(key)+&apos;::::&apos;+dict_id_url[key]+&apos;
&apos;) f_url_error_this_time.close() except (TimeoutError,urllib.error.URLError): print(&apos;----url失效，下载超时----&apos;) f_url_error_this_time = open(&quot;url_error_this_time.txt&quot;, &apos;a&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;) f_url_error_this_time.write(str(key) + &apos;::::&apos; + dict_id_url[key] + &apos;
&apos;) f_url_error_this_time.close() print(&apos;本次已下载&apos;+str(getLines(&apos;down_ok_this_time.txt&apos;))+&apos;条，本次下载url错误&apos;+str(getLines(&apos;url_error_this_time.txt&apos;))+&apos;条&apos;) print(&apos;已保存并跳过此条url，下载继续--&gt;&apos;) if(flag%1000==0): print(&apos;本次已下载&apos;+flag+&apos;条视频&apos;)print(&quot;****下载全部完成****&quot;) 小结数据集与代码，发布在github.

需求现在拥有了一一对应的id::::text（video_text_hash.txt）和id::::url（video_url_hash.txt）。需求是永远递增的嘛~~~将video_text_hash.txt中text内容的#hash拿出来，单独存成id::::text（id_text.txt）和id::::hash（id_hash.txt）PS:拿完#hash后剩下的text若为空则删除此条目 handle_text.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162636465666768697071727374import re#根据video_text_hash.txt将hash提取出来获得id_hash.txt和剩下的id_text.txt其中排除剩余为空的id_text_void.txtf_video_texts = open(&quot;video_text_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_text = open(&quot;id_text.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_text_void = open(&quot;id_text_void.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_hash = open(&quot;id_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def get_hashs(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListdef getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotList# for i in range(1,20):ii=0while 1: line_video_text = f_video_texts.readline() list_hash = [] if not line_video_text: break else: try: list_hash = get_hashs(line_video_text) #hash组成一个list list_text = getText(line_video_text) #text组成list str_text = str(list_text[0])+&apos;
&apos; str_hashs = &apos;&apos; for hash in list_hash: #遍历每句的每个hash str_hash1 = &apos;#&apos;+str(hash)+&apos; &apos; str_hashs += str(str_hash1) str_hash2 = &apos;#&apos; + str(hash) + &apos;
&apos; #还原hash str_text = str_text.replace(str_hash1,&quot;&quot;) #删除hash str_text = str_text.replace(str_hash2, &quot;
&quot;) except IndexError: print(&quot;error&quot;) if(str_text != &apos;
&apos;): f_text.write(str(getId(line_video_text)[0])+&apos;::::&apos;+str_text) f_hash.write(str(getId(line_video_text)[0])+&apos;::::&apos;+str_hashs+&apos;
&apos;) else: f_text_void.write(str(getId(line_video_text)[0])+&apos;
&apos;) ii+=1 if(ii%10000==0): print(ii)f_video_texts.close()f_text.close()f_text_void.close()f_hash.close() text处理对于id_text.txt里的text，还需要做以下操作，1、去除非英文字符。2、去除停顿词。3、小写化text。得到id_text_final.txt和被剔除的剩余为空的id存到id_text_final_void.txt。同时顺便得到清理后的id::::hashs文件id_hash_final.txt（顺便小写化） handle_text_final.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103import re#根据id_text.txt做文本处理获得id_text_final.txt和排除剩余为空的id_text_final_void.txt#顺便得到清理后的id::::hashs文件id_hash_final.txtf_video_texts = open(&quot;id_text.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_stop_word = open(&quot;stop_word.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash = open(&quot;id_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_text_final = open(&quot;id_text_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_text_final_void = open(&quot;id_text_final_void.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash_final = open(&quot;id_hash_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotList#解决.isalpha()方法对（unicode string，string.isalpha会根据字符串中的字符是否属于Unicode编码的LETTER区域来判断是否都由字母组成。# 所以得出的结果为True，不一定表示只有26个英文字母。）def isAlpha(word): try: return word.encode(&apos;ascii&apos;).isalpha() except UnicodeEncodeError: return Falselist_stop_word = []while 1: line_stop_word = f_stop_word.readline() if not line_stop_word: break else: list_stop_word.append(str(line_stop_word).replace(&quot;
&quot;,&apos;&apos;).lower())print(&quot;停用词列表生成成功&quot;)dict_hash = &#123;&#125;while 1: line_hash = f_id_hash.readline() if not line_hash: break else: dict_hash[getId(line_hash)[0]] = getText(line_hash)[0]print(&quot;hash字典生成成功&quot;)ii=0# for i in range(1,3):while 1: line_video_text = f_video_texts.readline() list_word = [] if not line_video_text: break else: try: list_text = str(getText(line_video_text)[0]) text_final = &apos;&apos; for s in list_text: if isAlpha(s): text_final += s elif s==&apos; &apos;: text_final += s #text字符串，包含多余空格 # print(text_final) list_word = text_final.split(&apos; &apos;) #分词，包含空字符 text_final = &apos;&apos; for word in list_word: if word == &apos;&apos;: continue elif word not in list_stop_word: text_final += word+&apos; &apos; if text_final != &apos;&apos;: str_hash = dict_hash[getId(line_video_text)[0]] #清除非全英文字母的hash rule = r&apos;#(.*?) &apos; list_hashs = re.findall(rule, str_hash) str_hash = &apos;&apos; for hash in list_hashs: flag = 1 for s in hash: if isAlpha(s): continue else: flag = 0 break if flag: str_hash += &apos;#&apos;+hash+&apos; &apos; if str_hash != &apos;&apos;: f_id_text_final.write(getId(line_video_text)[0]+&apos;::::&apos;+text_final+&apos;
&apos;) #将去除空结果的id::::text写入id_text_final.txt f_id_hash_final.write(getId(line_video_text)[0]+&apos;::::&apos;+str_hash+&apos;
&apos;) else: f_id_text_final_void.write(getId(line_video_text)[0]+&apos;
&apos;) #将空白结果id写入text_final_void.txt except IndexError: print(&quot;error&quot;) ii+=1 if(ii%10000==0): print(ii)# print(len(list_1)) #data1的id listf_video_texts.close()f_stop_word.close()f_id_hash.close()f_id_text_final.close()f_id_text_final_void.close()f_id_hash_final.close() 统计hash词频根据id_hash_final.txt做hash的词频统计得到count_hash.txt count.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647# 统计hash总数与词频import collectionsimport ref_id_hash_final = open(&quot;id_hash_final.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_count_hash = open(&quot;count_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []i=1# for i in range(0,5):while 1: line_id_hash = f_id_hash_final.readline() if not line_id_hash: break else: slotList += subString1(line_id_hash) #将所有HashTag存进list# print(slotList)result = collections.Counter(slotList) #词频统计#ss = str(result) #词频统计结果转换成字符串并存文件# f_handle_hash.write(ss)#print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) #词频统计结果转换成字符串并存文件 f_count_hash.write(ss+&apos;
&apos;) #print(ss)f_id_hash_final.close()f_count_hash.close() 截取指定长度数据集遍历id_hash_final.txt里的hash，走到最后一个频率为5的hash（premiosjuventud）停止首先生成对应的list与dict以供快速读取 get_list_or_dict.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788import re#id_text_final--&gt;dict_id_text_final#id_hash_final--&gt;dict_id_hash_final#count_hash--&gt;list_count_hash#video_url_hash--&gt;dict_id_urlf_id_text_final = open(&quot;id_text_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_text_final = open(&quot;dict_id_text_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_id_hash_final = open(&quot;id_hash_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_hash_final = open(&quot;dict_id_hash_final.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_count_hash = open(&quot;count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_count_hash = open(&quot;list_count_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_url = open(&quot;dict_id_url.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotListlist_hash = []while 1: line_hash = f_count_hash.readline() if not line_hash: break else: rule1 = r&quot;&apos;(.*?)&apos;&quot; rule2 = r&apos;&quot;(.*?)&quot;&apos; try: slotList = re.findall(rule1, line_hash) list_hash.append(str(slotList[0])) except IndexError: slotList = re.findall(rule2, line_hash) list_hash.append(str(slotList[0]))f_list_count_hash.write(str(list_hash))# print(len(list_1)) #data1的id listdict_id_text_final = &#123;&#125;dict_id_hash_final = &#123;&#125;ii=1while 1: line_id_text = f_id_text_final.readline() line_id_hash = f_id_hash_final.readline() if not line_id_text: break else: each_id = getId(line_id_text) each_text = getText(line_id_text) dict_id_text_final[each_id[0]] = each_text[0] each_id = getId(line_id_hash) each_text = getText(line_id_hash) dict_id_hash_final[each_id[0]] = each_text[0] ii += 1 if (ii % 50000 == 0): print(ii)f_dict_id_text_final.write(str(dict_id_text_final))f_dict_id_hash_final.write(str(dict_id_hash_final))# print(dict_id_text_final[&apos;980744748887429120&apos;]) #data2的dict &#123;id:text&#125;# print(dict_id_hash_final[&apos;980744748887429120&apos;])dict_id_url = &#123;&#125;ii=1while 1: line_id_url = f_video_url_hash.readline() if not line_id_url: break else: each_id = getId(line_id_url) each_text = getText(line_id_url) dict_id_url[each_id[0]] = each_text[0] ii += 1 if (ii % 50000 == 0): print(ii)f_dict_id_url.write(str(dict_id_url))# print(dict_id_url[&apos;980744748887429120&apos;]) #data2的dict &#123;id:text&#125;f_id_text_final.close()f_dict_id_text_final.close()f_id_hash_final.close()f_dict_id_hash_final.close()f_count_hash.close()f_list_count_hash.close()f_video_url_hash.close()f_dict_id_url.close() 最后得到一定数量的数据集final_id_texts/hashs/urls.txt get_final_urls.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576import re#根据count_hash.txt和id_hash_final.txt获得最终需要的一定数量的数据集final_id_texts/hashs/urls.txtf_dict_id_text_final = open(&quot;dict_id_text_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_hash_final = open(&quot;dict_id_hash_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_count_hash = open(&quot;list_count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_dict_id_url = open(&quot;dict_id_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_texts = open(&quot;final_texts.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_hashs = open(&quot;final_hashs.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_urls = open(&quot;final_urls.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotListlist_hash = []f = open(&quot;list_count_hash.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()list_hash = eval(a)f.close()print(&quot;list_count_hash读取成功
&quot;)print(len(list_hash))dict_id_text_final = &#123;&#125;f = open(&quot;dict_id_text_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_text_final = eval(a)f.close()print(&quot;dict_id_text_final读取成功
&quot;)dict_id_hash_final = &#123;&#125;f = open(&quot;dict_id_hash_final.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_hash_final = eval(a)f.close()print(&quot;dict_id_hash_final读取成功
&quot;)dict_id_url = &#123;&#125;f = open(&quot;dict_id_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)a = f.read()dict_id_url = eval(a)f.close()print(&quot;dict_id_url读取成功
&quot;)print(&quot;开始匹配&quot;)list_del = []iii=0for hash in list_hash: ii = 0 for key in dict_id_hash_final: if (str(&quot;#&quot;+hash+&quot; &quot;) in str(dict_id_hash_final[key])): f_final_texts.write(key + &apos;::::&apos; + dict_id_text_final[key] + &apos;
&apos;) f_final_hashs.write(key + &apos;::::&apos; + dict_id_hash_final[key] + &apos;
&apos;) f_final_urls.write(key + &apos;::::&apos; + dict_id_url[key] + &apos;
&apos;) ii+=1 list_del.append(key) for i_del in list_del: del dict_id_hash_final[i_del] list_del = [] iii+=ii print(str(hash)+&quot;--匹配结束，其写入--&quot;+str(ii)+&apos;--条--共计写入&apos;+str(iii)+&apos;条&apos;) if (str(hash) == &apos;premiosjuventud&apos;): breakf_dict_id_text_final.close()f_dict_id_hash_final.close()f_list_count_hash.close()f_dict_id_url.close()f_final_texts.close()f_final_hashs.close()f_final_urls.close() 再处理hash将final_hashs.txt复制到final_hashs1.txt将每条hashs中出现小于5次的hash删除得到最终final_hashs.txt clean_final_hashs.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556#对于final_hashs1.txt每条item清除频率少于5次的hashimport ref_final_hashs1 = open(&quot;final_hashs1.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_list_hash = open(&quot;count_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_final_hashs = open(&quot;final_hashs.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;::::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?)::::&apos; slotList = re.findall(rule, template) return slotListlist_hash = []# for i in range(0,5):while 1: line_id_hash = f_list_hash.readline() if not line_id_hash: break else: rule = r&quot;&apos;(.*?)&apos;&quot; list_hash += re.findall(rule, line_id_hash)print(&apos;list_hash生成成功&apos;)# for i in range(0,100):i=0while 1: line_hashs = f_final_hashs1.readline() list_hashs = [] str_hashs = &apos;&apos; if not line_hashs: break else: try: # str_hashs = str(getId(line_hashs)[0]) + &apos;::::&apos; rule = r&quot;#(.*?) &quot; list_hashs += re.findall(rule, line_hashs) for hash in list_hashs: if str(hash) in list_hash: str_hashs += &apos;#&apos; + str(hash) + &apos; &apos; if(str_hashs != &apos;&apos;): f_final_hashs.write(str(getId(line_hashs)[0]) + &apos;::::&apos;+str_hashs + &apos;
&apos;) else: print(&apos;------&apos;) i+=1 except IndexError: print(&quot;erro&quot;) if(i%10000==0): print(i)f_final_hashs1.close()f_list_hash.close()f_final_hashs.close() 小结到目前为止，获得了121117条一一对应的final_hashs/urls/texts.txt文件数据集与代码，发布在github.

问题描述有一个从vine.co爬取下来的数据集，需要对视频描述中的HashTag进行提取与计数 筛选首先筛选视频描述中拥有HashTag（以#开头的单词或短语）的条目 handle_data.py12345678910111213141516171819202122#得到带hash的视频描述与视频链接#解决编码问题，忽略警告f_video_text = open(&quot;video_text.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url = open(&quot;video_download_link.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)#要写入的文件f_video_text_hash = open(&quot;video_text_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)e = &apos;#&apos; #以‘#’号标识while 1:#分别读取下一行 line_video_text = f_video_text.readline() line_video_url = f_video_url.readline() if not line_video_text: break#如果包含HashTag if (e in line_video_text): f_video_text_hash.write(line_video_text) f_video_url_hash.write(line_video_url)f_video_url.close()f_video_text.close() 统计遍历得到的文件，提取所有的HashTag并做词频统计 handle_hash.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546# 统计hash总数与词频import collectionsf_video_text_hash = open(&quot;video_text_hash.txt&quot;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_handle_hash = open(&quot;handle_hash.txt&quot;, &apos;w&apos;, encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def subString1(template): # HashTag以‘#’开头，以空格或回车结尾 copy = False finished = False slotList = [] str = &quot;&quot; for s in template: if s == &apos;#&apos;: copy = True elif s == &apos; &apos;: copy = False finished = True elif s == &apos;
&apos;: copy = False finished = True elif copy: str = str + s if finished: if str != &quot;&quot;: slotList.append(str) str = &quot;&quot; finished = False return slotListslotList = []while 1: line_video_text = f_video_text_hash.readline() if not line_video_text: break else: slotList += subString1(line_video_text) #将所有HashTag存进listresult = collections.Counter(slotList) #词频统计#ss = str(result) #词频统计结果转换成字符串并存文件# f_handle_hash.write(ss)#print(result.most_common(100)) 查看统计结果前100名for each in result.most_common(): ss = str(each) #词频统计结果转换成字符串并存文件 f_handle_hash.write(ss+&apos;
&apos;) #print(ss)f_video_text_hash.close()f_handle_hash.close() 数据集2以上是处理数据集1：n条video:::text对应n条video:::url，顺序数量一一对应。后来又有了数据集2：n条video:::text对应m条video:::url,而且顺序不对应，两者间也不具备完全的包含关系。 筛选首先是获得含有hashtag的数据集合video_text_hash.txt get_video_text_hash.py12345678910111213#得到带hash的视频描述f_video_text = open(&quot;location_videos_description&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)e = &apos;#&apos;while 1: line_video_text = f_video_text.readline() if not line_video_text: break if (e in line_video_text): f_video_text_hash.write(line_video_text)f_video_text.close() 去重然后将这个数据集2的video_text_hash.txt（复制成video_text_hash_2.txt）和数据集1的video_text_hash.txt（复制成video_text_hash_1.txt）比较，去除重复条目得到video_text_hash_3.txt，重复的条目存到video_cover.txt get_video_text_hash_off_cover.py123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051import re#data1与data2的video_text_hash去重f1_video_text = open(&quot;video_text_hash_1.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_text_hash_2.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash_3.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_cover = open(&quot;video_cover.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = [] #用list存video_text_hash_1.txt的video的idwhile 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) list_1.append(each_id[0])#print(list_1) #data1的id listdict_2 = &#123;&#125; #用dict存video_text_hash_2.txt的video的id：texti=1while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0]#print(dict_2) #data2的dict &#123;id:text&#125;for key in dict_2: if(key not in list_1): f_video_text_hash.write(key + &apos;::&apos; + dict_2[key] + &apos;
&apos;) else: f_video_text_cover.write(key + &apos;::&apos; + dict_2[key] + &apos;
&apos;) i+=1 if(i%5000==0): print(i)f1_video_text.close()f2_video_text.close()f_video_text_hash.close() 获得url然后将这个数据集2的video_text_hash_3.txt（复制成video_text_hash_off_cover.txt）和数据集2的video_url.txt比较，找到缺失的url_id条目得到video_url_off.txt，清理的id_url存到video_url_hash.txt get_video_url_hash.py1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162import re#根据video_text_hash_off_cover.txt清洗video_url.txtf1_video_text = open(&quot;video_text_hash_off_cover.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_url.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_hash = open(&quot;video_url_hash.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_url_off = open(&quot;video_url_off.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = []while 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) list_1.append(each_id[0])#print(list_1) #data1的id listii=1dict_2 = &#123;&#125;while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0] ii += 1 if (ii % 5000 == 0): print(ii)#print(dict_2) #data2的dict &#123;id:text&#125;print(&quot;开始清洗&quot;)ii=1for i in list_1: if(i in dict_2): try: f_video_url_hash.write(i + &apos;::::&apos; + dict_2[i] + &apos;
&apos;) except IndexError: print(&quot;c1&quot;) else: try: f_video_url_off.write(i + &apos;
&apos;) except IndexError: print(&quot;c2&quot;) ii+=1 if(ii%5000==0): print(ii)f1_video_text.close()f2_video_text.close()f_video_url_hash.close() 获得text将video_text_hash_off_cover.txt依据video_url_off.txt清除缺失url的条目得到最终video_text_hash_4.txt get_video_text_hash_clean_again.py12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758import re#将video_text_hash_off_cover.txt依据video_url_off.txt清除缺失url项f1_video_text = open(&quot;video_url_off.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f2_video_text = open(&quot;video_text_hash_off_cover.txt&quot;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)f_video_text_hash = open(&quot;video_text_hash_4.txt&quot;,&apos;w&apos;,encoding=&apos;utf8&apos;, errors=&apos;ignore&apos;)def getText(template): rule = r&apos;:::(.*?)
&apos; slotList = re.findall(rule, template) return slotListdef getId(template): rule = r&apos;(.*?):::&apos; slotList = re.findall(rule, template) return slotListlist_1 = []while 1: line_video_text = f1_video_text.readline() if not line_video_text: break else: #each_id = getId(line_video_text) rule = r&apos;(.*?)
&apos; slotList = re.findall(rule, line_video_text) list_1.append(slotList[0])#print(list_1) #data1的id listdict_2 = &#123;&#125;list_2 = []ii=1while 1: line_video_text = f2_video_text.readline() if not line_video_text: break else: each_id = getId(line_video_text) each_text = getText(line_video_text) dict_2[each_id[0]] = each_text[0] list_2.append(each_id[0]) ii += 1 if (ii % 10000 == 0): print(ii)#print(list_2[0]) #data2的dict &#123;id:text&#125;ii=0for i in list_2: if(i in list_1): pass else: f_video_text_hash.write(i + &apos;:::&apos; + dict_2[i] + &apos;
&apos;) ii += 1 if (ii % 10000 == 0): print(ii)f1_video_text.close()f2_video_text.close()f_video_text_hash.close() 整合手动将数据集1得到的video:::text和video:::url文件（video_text_hash.txt,video_url_hash.txt），和数据集2得到的video:::text和video:::url文件（video_text_hash_4.txt,video_url_hash.txt）合并得到最终video_text_hash.txt和video_url_hash.txt。 小结目前只处理了这两类数据，数据集中还包含了用户信息之类的其他信息，发布在github.
